unit lipdecide;

{ Launch Interceptor Program (Knight & Leveson 1986) - DECIDE and REALCOMPARE.
  Single-file Free Pascal unit. Uses only globals and standard RTL (Math). }

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

{ ---------------------------------------------------------------------------
  REALCOMPARE: six-significant-digit comparison as required by the spec.
  Compares A and B using their six most significant figures.
  Returns LT, EQ, or GT.
--------------------------------------------------------------------------- }

function REALCOMPARE(A, B: real): COMPTYPE;
const
  LN10 = 2.302585092994046;  { ln(10) }
  MNZ  = 1.0E-99;            { minimum non-zero magnitude }
var
  sa, sb: integer;
  aabs, babs, m, e, sc: real;
  na, nb: int64;
begin
  { Determine signs }
  if A < 0 then
    sa := -1
  else if A > 0 then
    sa := 1
  else
    sa := 0;

  if B < 0 then
    sb := -1
  else if B > 0 then
    sb := 1
  else
    sb := 0;

  aabs := abs(A);
  babs := abs(B);

  { Zero cases }
  if (sa = 0) and (sb = 0) then
  begin
    REALCOMPARE := EQ;
    exit;
  end
  else if (sa = 0) and (sb <> 0) then
  begin
    if babs < MNZ then
      REALCOMPARE := EQ
    else
      REALCOMPARE := LT;
    exit;
  end
  else if (sa <> 0) and (sb = 0) then
  begin
    if aabs < MNZ then
      REALCOMPARE := EQ
    else
      REALCOMPARE := GT;
    exit;
  end
  else if sa < sb then
  begin
    REALCOMPARE := LT;
    exit;
  end
  else if sa > sb then
  begin
    REALCOMPARE := GT;
    exit;
  end;

  { Same sign, compare magnitudes with 6 sig figs }
  if aabs < babs then
    m := babs
  else
    m := aabs;

  if m < MNZ then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  { Scale to get 6 significant figures }
  e := floor(ln(m) / LN10);
  sc := exp(LN10 * (5.0 - e));           { 10^(5-e) }
  na := Trunc(0.5 + aabs * sc);
  nb := Trunc(0.5 + babs * sc);

  if na = nb then
  begin
    { Tie breaker for same 6 sig figs: use true magnitudes }
    if sa = -1 then
    begin
      if aabs > babs then
        REALCOMPARE := LT
      else if aabs < babs then
        REALCOMPARE := GT
      else
        REALCOMPARE := EQ;
    end
    else
    begin
      if aabs < babs then
        REALCOMPARE := LT
      else if aabs > babs then
        REALCOMPARE := GT
      else
        REALCOMPARE := EQ;
    end;
  end
  else if na < nb then
  begin
    if sa = -1 then
      REALCOMPARE := GT   { negative: smaller magnitude is larger value }
    else
      REALCOMPARE := LT;
  end
  else
  begin
    if sa = -1 then
      REALCOMPARE := LT   { negative: larger magnitude is smaller value }
    else
      REALCOMPARE := GT;
  end;
end;

{ Helper comparison functions using REALCOMPARE (as encouraged by spec) }

function R_Lt(const A, B: real): boolean; inline;
begin
  R_Lt := REALCOMPARE(A, B) = LT;
end;

function R_Le(const A, B: real): boolean; inline;
var
  c: COMPTYPE;
begin
  c := REALCOMPARE(A, B);
  R_Le := (c = LT) or (c = EQ);
end;

function R_Gt(const A, B: real): boolean; inline;
begin
  R_Gt := REALCOMPARE(A, B) = GT;
end;

function R_Ge(const A, B: real): boolean; inline;
var
  c: COMPTYPE;
begin
  c := REALCOMPARE(A, B);
  R_Ge := (c = GT) or (c = EQ);
end;

function R_Eq(const A, B: real): boolean; inline;
begin
  R_Eq := REALCOMPARE(A, B) = EQ;
end;

{ Geometry primitives - all comparisons MUST go through REALCOMPARE }

function DistP(x1, y1, x2, y2: real): real; inline;
begin
  DistP := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

function CrossTwice(x1, y1, x2, y2, x3, y3: real): real; inline;
begin
  CrossTwice := (x2 - x1) * (y3 - y1) - (y2 - y1) * (x3 - x1);
end;

{ Smallest enclosing circle radius for 3 points.
  If collinear: radius = half the longest side.
  Else: circumradius = abc / (4K) where K is triangle area. }
function MinEnclosingR3(x1, y1, x2, y2, x3, y3: real): real;
var
  d12, d23, d31, area, circumR, maxd: real;
begin
  d12 := DistP(x1, y1, x2, y2);
  d23 := DistP(x2, y2, x3, y3);
  d31 := DistP(x1, y1, x3, y3);
  area := 0.5 * abs(CrossTwice(x1, y1, x2, y2, x3, y3));

  if R_Eq(area, 0) then
  begin
    { Collinear - use half the longest side as radius }
    maxd := d12;
    if R_Gt(d23, maxd) then maxd := d23;
    if R_Gt(d31, maxd) then maxd := d31;
    MinEnclosingR3 := 0.5 * maxd;
  end
  else
  begin
    { Circumradius formula }
    circumR := (d12 * d23 * d31) / (4 * area);
    MinEnclosingR3 := circumR;
  end;
end;

{ Determine quadrant for LIC 5.
  Priority: I, II, III, IV.
  (0,0) and positive axes are in quadrant I. }
function Quadrant(x, y: real): integer;
var
  xcomp, ycomp: COMPTYPE;
begin
  xcomp := REALCOMPARE(x, 0);
  ycomp := REALCOMPARE(y, 0);

  if (xcomp = GT) or (xcomp = EQ) then
  begin
    if (ycomp = GT) or (ycomp = EQ) then
      Quadrant := 1  { I }
    else
      Quadrant := 4; { IV }
  end
  else
  begin
    if (ycomp = GT) or (ycomp = EQ) then
      Quadrant := 2  { II }
    else
      Quadrant := 3; { III }
  end;
end;

{ Check if angle formed by vectors (vx,vy) and (wx,wy) is NOT within
  [PI-EPSILON, PI+EPSILON]. Returns true if angle condition is satisfied. }
function InteriorAngleValid(vx, vy, wx, wy, eps: real): boolean;
var
  lenu, lenw, t, a: real;
begin
  lenu := sqrt(sqr(vx) + sqr(vy));
  lenw := sqrt(sqr(wx) + sqr(wy));

  if R_Eq(lenu, 0) or R_Eq(lenw, 0) then
  begin
    InteriorAngleValid := false;
    exit;
  end;

  t := (vx * wx + vy * wy) / (lenu * lenw);

  { Clamp cosine to valid range }
  if R_Lt(t, -1) then
    t := -1
  else if R_Gt(t, 1) then
    t := 1;

  a := arccos(t);

  { Angle condition: a < (PI - EPSILON) or a > (PI + EPSILON) }
  { But since a is in [0, PI], we check a < (PI - EPSILON) }
  InteriorAngleValid := R_Lt(a, PI - eps);
end;

{ Distance from point (px,py) to line through (ax,ay)-(bx,by).
  If endpoints coincide, returns distance to that point. }
function LineDist(ax, ay, bx, by, px, py: real): real;
var
  vx, vy, wx, wy, c, len: real;
begin
  vx := bx - ax;
  vy := by - ay;
  wx := px - ax;
  wy := py - ay;
  len := sqrt(sqr(vx) + sqr(vy));

  if R_Eq(len, 0) then
    LineDist := DistP(ax, ay, px, py)
  else
  begin
    c := abs(vx * wy - vy * wx);
    LineDist := c / len;
  end;
end;

{ Evaluate all 15 LICs and set CMV[i] accordingly.
  All real comparisons MUST use REALCOMPARE or the R_* helpers. }
procedure EvalCMV;
var
  i, j, s, c, p2, p3, q, cnt, h, nq, k: integer;
  b1, b2: boolean;
  d, L1, L2, R, ar, x1, y1, x2, y2: real;
  inwin: array[1..4] of boolean;
begin
  L1 := PARAMETERS.LENGTH1;

  { LIC 1: two consecutive points > LENGTH1 apart }
  b1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := DistP(X[i], Y[i], X[i + 1], Y[i + 1]);
    if R_Gt(d, L1) then
    begin
      b1 := true;
      break;
    end;
  end;
  CMV[1] := b1;

  { LIC 2: three consecutive points cannot fit in circle of RADIUS1 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      R := MinEnclosingR3(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
      if R_Gt(R, PARAMETERS.RADIUS1) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[2] := b1;

  { LIC 3: three consecutive points form angle < (PI-EPSILON) or > (PI+EPSILON)
    Vertex is always the middle point. If vertex coincides with endpoint,
    angle is undefined and condition is not satisfied for that triplet. }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      x1 := X[i] - X[i + 1];
      y1 := Y[i] - Y[i + 1];
      x2 := X[i + 2] - X[i + 1];
      y2 := Y[i + 2] - Y[i + 1];
      if InteriorAngleValid(x1, y1, x2, y2, PARAMETERS.EPSILON) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[3] := b1;

  { LIC 4: three consecutive points form triangle with area > AREA1 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      ar := 0.5 * abs(CrossTwice(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]));
      if R_Gt(ar, PARAMETERS.AREA1) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[4] := b1;

  { LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
  b1 := false;
  if NUMPOINTS >= PARAMETERS.Q_PTS then
  begin
    q := PARAMETERS.Q_PTS;
    c := PARAMETERS.QUADS;
    for s := 1 to NUMPOINTS - q + 1 do
    begin
      for h := 1 to 4 do
        inwin[h] := false;
      for j := 0 to q - 1 do
      begin
        k := s + j;
        cnt := Quadrant(X[k], Y[k]);
        inwin[cnt] := true;
      end;
      nq := 0;
      for h := 1 to 4 do
        if inwin[h] then
          Inc(nq);
      if nq > c then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[5] := b1;

  { LIC 6: two consecutive points with X[j] - X[i] < 0 (i = j-1) }
  b1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if R_Lt(X[i + 1] - X[i], 0) then
    begin
      b1 := true;
      break;
    end;
  end;
  CMV[6] := b1;

  { LIC 7: N_PTS consecutive points, at least one > DIST from line between first and last.
    Special case if first and last coincide. }
  b1 := false;
  if (NUMPOINTS >= 3) and (PARAMETERS.N_PTS <= NUMPOINTS) then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      x1 := X[s];
      y1 := Y[s];
      x2 := X[s + PARAMETERS.N_PTS - 1];
      y2 := Y[s + PARAMETERS.N_PTS - 1];
      for j := 1 to PARAMETERS.N_PTS - 2 do
      begin
        c := s + j;
        d := LineDist(x1, y1, x2, y2, X[c], Y[c]);
        if R_Gt(d, PARAMETERS.DIST) then
        begin
          b1 := true;
          break;
        end;
      end;
      if b1 then break;
    end;
  end;
  CMV[7] := b1;

  { LIC 8: two points separated by exactly K_PTS intervening points > LENGTH1 apart }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    c := PARAMETERS.K_PTS;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2 := i + c + 1;
      d := DistP(X[i], Y[i], X[p2], Y[p2]);
      if R_Gt(d, L1) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[8] := b1;

  { LIC 9: three points separated by A_PTS and B_PTS, cannot fit in RADIUS1 circle }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      p2 := s + PARAMETERS.A_PTS + 1;
      p3 := p2 + PARAMETERS.B_PTS + 1;
      R := MinEnclosingR3(X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]);
      if R_Gt(R, PARAMETERS.RADIUS1) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[9] := b1;

  { LIC 10: three points separated by C_PTS and D_PTS with angle condition }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      p2 := s + PARAMETERS.C_PTS + 1;
      p3 := p2 + PARAMETERS.D_PTS + 1;
      x1 := X[s] - X[p2];
      y1 := Y[s] - Y[p2];
      x2 := X[p3] - X[p2];
      y2 := Y[p3] - Y[p2];
      if InteriorAngleValid(x1, y1, x2, y2, PARAMETERS.EPSILON) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[10] := b1;

  { LIC 11: three points separated by E_PTS and F_PTS with area > AREA1 }
  b1 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      p2 := s + PARAMETERS.E_PTS + 1;
      p3 := p2 + PARAMETERS.F_PTS + 1;
      ar := 0.5 * abs(CrossTwice(X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]));
      if R_Gt(ar, PARAMETERS.AREA1) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[11] := b1;

  { LIC 12: two points separated by G_PTS with X[j] - X[i] < 0 }
  b1 := false;
  if NUMPOINTS >= 3 then
  begin
    c := PARAMETERS.G_PTS;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2 := i + c + 1;
      if R_Lt(X[p2] - X[i], 0) then
      begin
        b1 := true;
        break;
      end;
    end;
  end;
  CMV[12] := b1;

  { LIC 13: exists pair > LENGTH1 AND exists pair < LENGTH2 (K_PTS separation) }
  b1 := false;
  b2 := false;
  L2 := PARAMETERS.LENGTH2;
  if NUMPOINTS >= 3 then
  begin
    c := PARAMETERS.K_PTS;
    for i := 1 to NUMPOINTS - c - 1 do
    begin
      p2 := i + c + 1;
      d := DistP(X[i], Y[i], X[p2], Y[p2]);
      if (not b1) and R_Gt(d, L1) then b1 := true;
      if (not b2) and R_Lt(d, L2) then b2 := true;
      if b1 and b2 then break;
    end;
  end;
  CMV[13] := b1 and b2;

  { LIC 14: exists triple with R > RADIUS1 AND exists triple with R <= RADIUS2 }
  b1 := false;
  b2 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      p2 := s + PARAMETERS.A_PTS + 1;
      p3 := p2 + PARAMETERS.B_PTS + 1;
      R := MinEnclosingR3(X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]);
      if (not b1) and R_Gt(R, PARAMETERS.RADIUS1) then b1 := true;
      if (not b2) and R_Le(R, PARAMETERS.RADIUS2) then b2 := true;
      if b1 and b2 then break;
    end;
  end;
  CMV[14] := b1 and b2;

  { LIC 15: exists triple with area > AREA1 AND exists triple with area < AREA2 }
  b1 := false;
  b2 := false;
  if NUMPOINTS >= 5 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      p2 := s + PARAMETERS.E_PTS + 1;
      p3 := p2 + PARAMETERS.F_PTS + 1;
      ar := 0.5 * abs(CrossTwice(X[s], Y[s], X[p2], Y[p2], X[p3], Y[p3]));
      if (not b1) and R_Gt(ar, PARAMETERS.AREA1) then b1 := true;
      if (not b2) and R_Lt(ar, PARAMETERS.AREA2) then b2 := true;
      if b1 and b2 then break;
    end;
  end;
  CMV[15] := b1 and b2;
end;

{ Main DECIDE procedure - implements the full K&L decision logic.
  Reads from globals, writes CMV, PUM, FUV, LAUNCH. }
procedure DECIDE;
var
  i, j: integer;
  row, all: boolean;
  op: CONNECTORS;
  ci, cj: boolean;
begin
  { Initialize all outputs to false (defensive) }
  for i := 1 to 15 do
    CMV[i] := false;
  for i := 1 to 15 do
    for j := 1 to 15 do
      PUM[i, j] := false;
  for i := 1 to 15 do
    FUV[i] := false;
  LAUNCH := false;

  { Step 1: Compute Conditions Met Vector (CMV) }
  EvalCMV;

  { Step 2: Compute Preliminary Unlocking Matrix (PUM) off-diagonal elements
    from LCM and CMV. Diagonal elements were provided as input. }
  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
      begin
        op := LCM[i, j];
        ci := CMV[i];
        cj := CMV[j];
        if op = NOTUSED then
          PUM[i, j] := true
        else if op = ANDD then
          PUM[i, j] := ci and cj
        else { ORR }
          PUM[i, j] := ci or cj;
      end;

  { Step 3: Compute Final Unlocking Vector (FUV)
    FUV[i] = true if PUM[i,i] = false OR entire row i of PUM is true }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      row := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          row := false;
          break;
        end;
      FUV[i] := row;
    end;
  end;

  { Step 4: Final launch decision - LAUNCH iff all FUV[i] are true }
  all := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      all := false;
      break;
    end;
  LAUNCH := all;
end;

end.
